// frontend/src/components/vouchers/MyVouchers.js
import React, { useState, useEffect } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import api from '../../services/api';
import { useAuth } from '../../contexts/AuthContext';
import { useAlert } from '../../contexts/AlertContext';
import './Voucher.css';

const MyVouchers = () => {
    const { user } = useAuth();
    const alert = useAlert();
    const navigate = useNavigate();

    const [vouchers, setVouchers] = useState([]);
    const [stats, setStats] = useState({ total: 0, active: 0, total_balance: 0 });
    const [loading, setLoading] = useState(true);
    const [error, setError] = useState('');

    // Modal states for claim
    const [showClaimModal, setShowClaimModal] = useState(false);
    const [selectedVoucher, setSelectedVoucher] = useState(null);
    const [claimAmount, setClaimAmount] = useState(0);
    const [claimMethod, setClaimMethod] = useState('bank');
    const [claimLoading, setClaimLoading] = useState(false);

    // Modal states for history
    const [showHistoryModal, setShowHistoryModal] = useState(false);
    const [voucherHistory, setVoucherHistory] = useState([]);
    const [historyLoading, setHistoryLoading] = useState(false);

    useEffect(() => {
        loadVouchers();
    }, []);

    const loadVouchers = async () => {
        setLoading(true);
        try {
            const response = await api.get('/vouchers/my');
            if (response.data.success) {
                setVouchers(response.data.data.vouchers);
                setStats(response.data.data.stats);
            } else {
                setError('Failed to load vouchers');
            }
        } catch (error) {
            console.error('Error loading vouchers:', error);
            setError('Network error');
        } finally {
            setLoading(false);
        }
    };

    const loadVoucherHistory = async (voucherId) => {
        setHistoryLoading(true);
        try {
            const response = await api.get(`/vouchers/${voucherId}/transactions`);
            if (response.data.success) {
                setVoucherHistory(response.data.data);
            }
        } catch (error) {
            console.error('Error loading history:', error);
            alert.error('Failed to load transaction history');
        } finally {
            setHistoryLoading(false);
        }
    };

    const handleUseVoucher = (voucher) => {
        navigate('/jobs', { 
            state: { 
                useVoucher: voucher,
                amount: voucher.current_balance 
            } 
        });
    };

    const handleClaimVoucher = (voucher) => {
        setSelectedVoucher(voucher);
        setClaimAmount(voucher.current_balance);
        setShowClaimModal(true);
    };

    const handleViewHistory = async (voucher) => {
        setSelectedVoucher(voucher);
        await loadVoucherHistory(voucher.id);
        setShowHistoryModal(true);
    };

    const handleProcessClaim = async () => {
        if (!selectedVoucher) return;

        if (claimAmount < 20) {
            alert.warning('Minimum claim amount is R20');
            return;
        }

        if (claimAmount > selectedVoucher.current_balance) {
            alert.warning('Amount exceeds voucher balance');
            return;
        }

        setClaimLoading(true);
        try {
            const response = await api.post('/vouchers/claim', {
                voucher_id: selectedVoucher.id,
                amount: claimAmount,
                claim_method: claimMethod
            });

            if (response.data.success) {
                alert.success(`✅ Successfully claimed R${claimAmount}! You will receive R${response.data.data.net_amount} after fees.`);
                setShowClaimModal(false);
                setSelectedVoucher(null);
                loadVouchers(); // Refresh vouchers
            }
        } catch (error) {
            console.error('Claim error:', error);
            alert.error(error.response?.data?.message || 'Failed to claim voucher');
        } finally {
            setClaimLoading(false);
        }
    };

    const formatDate = (dateString) => {
        const date = new Date(dateString);
        return date.toLocaleDateString('en-ZA', {
            day: 'numeric',
            month: 'short',
            year: 'numeric',
            hour: '2-digit',
            minute: '2-digit'
        });
    };

    const getCardType = (faceValue) => {
        if (faceValue >= 1000) return 'premium';
        if (faceValue >= 500) return 'standard';
        return 'small';
    };

    const getStatusDisplay = (voucher) => {
        switch(voucher.current_status) {
            case 'active':
                return { text: '✅ Active', class: 'status-active' };
            case 'partially_used':
                return { text: '⚡ Partially Used', class: 'status-partially_used' };
            case 'used':
                return { text: '💫 Used', class: 'status-used' };
            case 'expired':
                return { text: '⏰ Expired', class: 'status-expired' };
            default:
                return { text: voucher.status, class: '' };
        }
    };

    if (loading) {
        return (
            <div className="voucher-container">
                <div className="loading-spinner">Loading your vouchers...</div>
            </div>
        );
    }

    return (
        <div className="my-vouchers-container">
            <div className="vouchers-header">
                <h1>My Vouchers</h1>
                <Link to="/vouchers/buy" className="btn-buy">
                    + Buy New Voucher
                </Link>
            </div>

            {error && <div className="voucher-error">{error}</div>}

            {/* Stats Cards */}
            <div className="voucher-stats">
                <div className="stat-card">
                    <span className="stat-value">{stats.total}</span>
                    <span className="stat-label">Total Vouchers</span>
                </div>
                <div className="stat-card">
                    <span className="stat-value">{stats.active}</span>
                    <span className="stat-label">Active</span>
                </div>
                <div className="stat-card">
                    <span className="stat-value">R {stats.total_balance.toLocaleString()}</span>
                    <span className="stat-label">Total Balance</span>
                </div>
            </div>

            {/* Vouchers Grid */}
            {vouchers.length === 0 ? (
                <div className="no-vouchers">
                    <div className="no-vouchers-icon">🎫</div>
                    <h3>You don't have any vouchers yet</h3>
                    <p>Buy your first voucher to start paying for jobs securely</p>
                    <Link to="/vouchers/buy" className="btn-primary">
                        Buy Your First Voucher
                    </Link>
                </div>
            ) : (
                <div className="vouchers-grid">
                    {vouchers.map(voucher => {
                        const cardType = getCardType(voucher.face_value);
                        const status = getStatusDisplay(voucher);

                        return (
                            <div key={voucher.id} className={`voucher-card ${cardType}`}>
                                {/* Status Badge */}
                                <div className={`voucher-status ${status.class}`}>
                                    {status.text}
                                </div>

                                {/* Card Header */}
                                <div className="voucher-header">
                                    <div className="voucher-title">
                                        <span>{voucher.template_name || 'KasiConnect Voucher'}</span>
                                        <span className="voucher-type-badge">
                                            R {voucher.face_value}
                                        </span>
                                    </div>

                                    {/* Voucher Code */}
                                    <div className="voucher-code-display">
                                        <div className="voucher-code-label">Voucher Number</div>
                                        <div className="voucher-code-value">{voucher.voucher_code}</div>
                                    </div>

                                    {/* PIN Display */}
                                    {voucher.pin_code && (
                                        <div className="voucher-pin">
                                            <span className="voucher-pin-label">
                                                <span role="img" aria-label="lock">🔐</span> PIN Code
                                            </span>
                                            <span className="voucher-pin-value">{voucher.pin_code}</span>
                                        </div>
                                    )}
                                </div>

                                {/* Card Body */}
                                <div className="voucher-body">
                                    {/* Balance */}
                                    <div className="voucher-balance">
                                        <span className="voucher-balance-label">Current Balance</span>
                                        <span className="voucher-balance-amount">
                                            R {voucher.current_balance.toLocaleString()}
                                        </span>
                                    </div>

                                    {/* Details Grid */}
                                    <div className="voucher-details-grid">
                                        <div className="voucher-detail-item">
                                            <span className="voucher-detail-label">Face Value</span>
                                            <span className="voucher-detail-value">
                                                R {voucher.face_value.toLocaleString()}
                                            </span>
                                        </div>
                                        <div className="voucher-detail-item">
                                            <span className="voucher-detail-label">Expires</span>
                                            <span className="voucher-detail-value">
                                                {new Date(voucher.expires_at).toLocaleDateString()}
                                            </span>
                                        </div>
                                        {voucher.used_percentage && (
                                            <div className="voucher-detail-item">
                                                <span className="voucher-detail-label">Used</span>
                                                <span className="voucher-detail-value">
                                                    {voucher.used_percentage}%
                                                </span>
                                            </div>
                                        )}
                                        <div className="voucher-detail-item">
                                            <span className="voucher-detail-label">Created</span>
                                            <span className="voucher-detail-value">
                                                {new Date(voucher.created_at).toLocaleDateString()}
                                            </span>
                                        </div>
                                    </div>
                                </div>

                                {/* Card Footer - Actions */}
                                <div className="voucher-footer">
                                    {voucher.current_status === 'active' && voucher.current_balance > 0 ? (
                                        <>
                                            <button 
                                                className="btn-use"
                                                onClick={() => handleUseVoucher(voucher)}
                                            >
                                                💳 Use for Payment
                                            </button>
                                            <button 
                                                className="btn-claim"
                                                onClick={() => handleClaimVoucher(voucher)}
                                            >
                                                💰 Claim Cash
                                            </button>
                                        </>
                                    ) : (
                                        <button 
                                            className="btn-history"
                                            onClick={() => handleViewHistory(voucher)}
                                        >
                                            📜 View History
                                        </button>
                                    )}
                                </div>
                            </div>
                        );
                    })}
                </div>
            )}

            {/* Instructions */}
            <div className="voucher-instructions">
                <h4>How to Use Vouchers</h4>
                <ol>
                    <li>Select a job and choose "Pay with Voucher"</li>
                    <li>Enter your voucher code and PIN</li>
                    <li>The amount will be deducted from your balance</li>
                    <li>Worker receives payment confirmation</li>
                    <li>You can check balance anytime via USSD</li>
                </ol>
            </div>



            {/* History Modal */}
            {showHistoryModal && selectedVoucher && (
                <div className="modal-overlay" onClick={() => setShowHistoryModal(false)}>
                    <div className="history-modal" onClick={e => e.stopPropagation()}>
                        <div className="modal-header">
                            <h2>📜 Transaction History</h2>
                            <button className="modal-close" onClick={() => setShowHistoryModal(false)}>×</button>
                        </div>

                        <div className="modal-body">
                            <div className="voucher-summary">
                                <p><strong>Voucher:</strong> {selectedVoucher.voucher_code}</p>
                                <p><strong>Current Balance:</strong> R {selectedVoucher.current_balance.toLocaleString()}</p>
                            </div>

                            {historyLoading ? (
                                <div className="loading-spinner-small">Loading history...</div>
                            ) : voucherHistory.length === 0 ? (
                                <div className="no-history">
                                    <p>No transactions found for this voucher</p>
                                </div>
                            ) : (
                                <div className="history-list">
                                    {voucherHistory.map((transaction, index) => (
                                        <div key={index} className="history-item">
                                            <div className="history-header">
                                                <span className="history-type">{transaction.transaction_type}</span>
                                                <span className="history-date">{formatDate(transaction.created_at)}</span>
                                            </div>
                                            <div className="history-details">
                                                <span className="history-amount">
                                                    {transaction.amount > 0 ? '+' : ''}R {transaction.amount}
                                                </span>
                                                <span className="history-balance">
                                                    Balance: R {transaction.new_balance}
                                                </span>
                                            </div>
                                            {transaction.reference && (
                                                <div className="history-reference">
                                                    Ref: {transaction.reference}
                                                </div>
                                            )}
                                        </div>
                                    ))}
                                </div>
                            )}
                        </div>
                    </div>
                </div>
            )}
        </div>
    );
};

export default MyVouchers;
